-- Get the generated user IDs
DO $$
DECLARE
    user_rec RECORD;
BEGIN
    FOR user_rec IN SELECT username, id FROM public.users WHERE role = 'ASHA' LOOP
        EXECUTE format('CREATE TEMP TABLE IF NOT EXISTS user_id_map (username TEXT, user_id INTEGER);');
        EXECUTE format('INSERT INTO user_id_map VALUES (%L, %s);', user_rec.username, user_rec.id);
    END LOOP;
END $$;


