-- Get the generated facility IDs
CREATE TEMP TABLE facility_id_map (facility_id INTEGER, ward_code VARCHAR(10));
INSERT INTO facility_id_map (facility_id, ward_code)
SELECT id, ward_code FROM public.facilities ORDER BY id;


-- Capacity Reports
INSERT INTO public.capacity_reports (facility_id, report_date, beds_total, beds_available, icu_total, icu_available, ventilators_total, ventilators_available, oxygen_available, disease_counts, created_at)
SELECT
    f.facility_id,
    generate_series(CURRENT_DATE - INTERVAL '30 days', CURRENT_DATE, '1 day'::interval)::date AS report_date,
    floor(random() * 150 + 50)::int AS beds_total,
    floor(random() * 40 + 10)::int AS beds_available,
    floor(random() * 20 + 10)::int AS icu_total,
    floor(random() * 8 + 2)::int AS icu_available,
    floor(random() * 10 + 5)::int AS ventilators_total,
    floor(random() * 3 + 1)::int AS ventilators_available,
    random() > 0.2 AS oxygen_available,
    jsonb_build_object('fever', floor(random() * 30)::int, 'cough', floor(random() * 20)::int, 'diarrhea', floor(random() * 15)::int) AS disease_counts,
    NOW() AS created_at
FROM facility_id_map f
CROSS JOIN generate_series(CURRENT_DATE - INTERVAL '30 days', CURRENT_DATE, '1 day'::interval);


-- Facility Inventory (with critical and low stock for some facilities)
INSERT INTO public.facility_inventory (facility_id, resource_type, current_stock, min_threshold, last_updated)
SELECT
    f.facility_id,
    unnest(ARRAY['Antipyretic', 'Cough Syrup', 'ORS', 'RDT Kit']) AS resource_type,
    CASE
        WHEN f.facility_id % 3 = 1 THEN floor(random() * 30)::int  -- critically low
        WHEN f.facility_id % 3 = 2 THEN floor(random() * 60 + 40)::int  -- low
        ELSE floor(random() * 500 + 200)::int  -- healthy
    END AS current_stock,
    100 AS min_threshold,
    NOW() - (random() * INTERVAL '30 days') AS last_updated
FROM facility_id_map f
CROSS JOIN generate_series(1, 4);


-- ASHA Reports (coordinates generated inside ward polygons)
INSERT INTO public.asha_reports (worker_id, ward_code, report_date, fever_count, cough_count, diarrhea_count, jaundice_count, rash_count, maternal_risk_flags, child_risk_flags, environmental_flags, location_lat, location_lng, disease_type, reporting_form, photo_paths)
SELECT
    u.id AS worker_id,
    u.ward_code,
    report_date,
    fever_count,
    cough_count,
    diarrhea_count,
    jaundice_count,
    rash_count,
    maternal_risk_flags,
    child_risk_flags,
    environmental_flags,
    ST_X(point) AS location_lat,
    ST_Y(point) AS location_lng,
    disease_type,
    reporting_form,
    '[]'::jsonb AS photo_paths
FROM (
    SELECT
        u.id,
        u.ward_code,
        generate_series(CURRENT_DATE - INTERVAL '30 days', CURRENT_DATE, '1 day'::interval)::date AS report_date,
        CASE WHEN random() < 0.05 THEN floor(random() * 100 + 50)::int ELSE floor(random() * 12)::int END AS fever_count,
        CASE WHEN random() < 0.05 THEN floor(random() * 80 + 40)::int ELSE floor(random() * 10)::int END AS cough_count,
        CASE WHEN random() < 0.05 THEN floor(random() * 60 + 30)::int ELSE floor(random() * 8)::int END AS diarrhea_count,
        floor(random() * 3)::int AS jaundice_count,
        floor(random() * 2)::int AS rash_count,
        CASE WHEN random() > 0.7 THEN jsonb_build_object('high_risk_pregnancies', floor(random() * 2)::int) ELSE NULL END AS maternal_risk_flags,
        CASE WHEN random() > 0.8 THEN jsonb_build_object('malnourished', floor(random() * 3)::int) ELSE NULL END AS child_risk_flags,
        CASE WHEN random() > 0.9 THEN jsonb_build_object('stagnant_water', random() > 0.5) ELSE NULL END AS environmental_flags,
        CASE WHEN random() < 0.1 THEN 'Dengue' WHEN random() < 0.2 THEN 'Malaria' ELSE 'General Fever' END AS disease_type,
        CASE WHEN random() < 0.33 THEN 'S' WHEN random() < 0.66 THEN 'P' ELSE 'L' END AS reporting_form,
        ST_GeneratePoints(w.geom, 1) AS point
    FROM public.users u
    JOIN public.wards w ON u.ward_code = w.code
    WHERE u.role = 'ASHA'
) t;


-- Alerts
INSERT INTO public.alerts (type, severity, ward_code, title, description, generated_at, acknowledged_at, resolved_at, status)
SELECT
    (ARRAY['resource', 'outbreak', 'info'])[floor(random() * 3 + 1)] AS type,
    (ARRAY['low', 'medium', 'high', 'critical'])[floor(random() * 4 + 1)] AS severity,
    CASE WHEN random() < 0.7 THEN (SELECT code FROM public.wards ORDER BY random() LIMIT 1) ELSE NULL END AS ward_code,
    'Alert ' || floor(random() * 1000)::int AS title,
    'Automatically generated alert description' AS description,
    NOW() - (random() * INTERVAL '30 days') AS generated_at,
    CASE WHEN random() < 0.3 THEN NOW() - (random() * INTERVAL '20 days') ELSE NULL END AS acknowledged_at,
    CASE WHEN random() < 0.2 THEN NOW() - (random() * INTERVAL '10 days') ELSE NULL END AS resolved_at,
    (ARRAY['active', 'acknowledged', 'resolved'])[floor(random() * 3 + 1)] AS status
FROM generate_series(1, 100);


-- Advisories
INSERT INTO public.advisories (title, description, severity, ward_code, published_at, expires_at, published_by)
SELECT
    'Health Advisory: ' || (ARRAY['Dengue Prevention', 'COVID-19 Booster', 'Heatwave Alert', 'Monsoon Precautions', 'Vaccination Camp'])[floor(random() * 5 + 1)] AS title,
    'Detailed advisory description goes here.' AS description,
    (ARRAY['low', 'medium', 'high'])[floor(random() * 3 + 1)] AS severity,
    CASE WHEN random() < 0.5 THEN (SELECT code FROM public.wards ORDER BY random() LIMIT 1) ELSE NULL END AS ward_code,
    NOW() - (random() * INTERVAL '60 days') AS published_at,
    CASE WHEN random() < 0.7 THEN NOW() + (random() * INTERVAL '30 days') ELSE NULL END AS expires_at,
    (ARRAY['MHO Solapur', 'SMC Health Dept', 'Epidemiologist', 'ICDS'])[floor(random() * 4 + 1)] AS published_by
FROM generate_series(1, 50);


-- Outbreak Events
INSERT INTO public.outbreak_events (ward_code, disease_type, status, declared_date, center_lat, center_lng, containment_radius_meters, last_update, is_closed)
SELECT
    code,
    (ARRAY['Dengue', 'Malaria', 'Typhoid', 'Cholera', 'COVID-19'])[floor(random() * 5 + 1)] AS disease_type,
    (ARRAY['investigative', 'active', 'resolved'])[floor(random() * 3 + 1)] AS status,
    CURRENT_DATE - (random() * INTERVAL '60 days')::int AS declared_date,
    ST_X(ST_Centroid(geom)) + (random() - 0.5) * 0.005 AS center_lat,
    ST_Y(ST_Centroid(geom)) + (random() - 0.5) * 0.005 AS center_lng,
    floor(random() * 500 + 500)::int AS containment_radius_meters,
    'Outbreak investigation in progress.' AS last_update,
    random() < 0.3 AS is_closed
FROM public.wards
WHERE random() < 0.5;


