-- Outbreak Predictions
INSERT INTO public.outbreak_predictions (ward_code, prediction_date, predicted_cases, confidence_lower, confidence_upper, model_version)
SELECT
    code,
    generate_series(CURRENT_DATE, CURRENT_DATE + INTERVAL '7 days', '1 day'::interval)::date AS prediction_date,
    floor(random() * 30 + 5)::int AS predicted_cases,
    floor(random() * 15)::int AS confidence_lower,
    floor(random() * 45 + 10)::int AS confidence_upper,
    'linear_v1' AS model_version
FROM public.wards;


-- Resource Demand Forecast
INSERT INTO public.resource_demand_forecast (ward_code, resource_type, forecast_date, predicted_demand)
SELECT
    w.code,
    unnest(ARRAY['Antipyretic', 'Cough Syrup', 'ORS', 'RDT Kit']) AS resource_type,
    generate_series(CURRENT_DATE, CURRENT_DATE + INTERVAL '7 days', '1 day'::interval)::date AS forecast_date,
    floor(random() * 50 + 10)::int AS predicted_demand
FROM public.wards w
CROSS JOIN generate_series(1, 4);


-- System Audit Logs
INSERT INTO public.system_audit_logs (user_id, action_type, description)
SELECT
    id,
    (ARRAY['LOGIN', 'REPORT_SUBMIT', 'DATA_SYNC', 'VIEW_DASHBOARD'])[floor(random() * 4 + 1)] AS action_type,
    'User performed action ' || (ARRAY['logged in', 'submitted report', 'synced data', 'viewed dashboard'])[floor(random() * 4 + 1)] AS description
FROM public.users
WHERE random() < 0.5
LIMIT 50;


